1000 
1001   KnownBits Known2(BitWidth);
1002   switch (I->getOpcode()) {
1003   default: break;
1004   case Instruction::Load:
1005     if (MDNode *MD =
1006             Q.IIQ.getMetadata(cast<LoadInst>(I), LLVMContext::MD_range))
1007       computeKnownBitsFromRangeMetadata(*MD, Known);
